import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { EcommerceService } from '../../services/ecommerce.service';

@Component({
  selector: 'app-header',
  standalone: true,
  imports: [CommonModule, RouterLink],
  template: `
    <header class="header">
      <div class="container">
        <!-- Logo with Base64 image -->
        <a routerLink="/products" class="logo">
          <img 
            [src]="logoBase64" 
            alt="CordiCart Logo" 
            class="logo-img">
        </a>
        
        <div class="search-bar">
          <input #searchInput type="text" placeholder="Search products..." (keyup.enter)="search(searchInput.value)">
          <button (click)="search(searchInput.value)">🔍</button>
        </div>
        
        <div class="nav-links">
          <a routerLink="/cart" class="cart-link">🛒 Cart ({{ cartCount() }})</a>
          
          @if (!isLoggedIn()) {
            <a routerLink="/login">Login</a>
            <a routerLink="/register">Register</a>
          } @else {
            <span class="username">Hi, {{ username() }}</span>
            <button (click)="logout()" class="logout-btn">Logout</button>
          }
        </div>
      </div>
    </header>
  `,
  styles: [`
    .header { 
      background: #ee4d2d; 
      padding: 12px 20px; 
      color: white; 
      position: sticky; 
      top: 0; 
      z-index: 1000; 
    }
    .container { 
      max-width: 1200px; 
      margin: 0 auto; 
      display: flex; 
      align-items: center; 
      justify-content: space-between; 
      gap: 20px; 
      flex-wrap: wrap; 
    }
    
    .logo { 
      display: flex; 
      align-items: center; 
      text-decoration: none; 
    }
    .logo-img { 
      height: 55px; 
      width: auto; 
      max-width: 220px; 
      object-fit: contain; 
    }
    
    @media (max-width: 768px) {
      .logo-img { 
        height: 45px; 
        max-width: 180px; 
      }
    }
    
    .search-bar { 
      flex: 1; 
      max-width: 500px; 
      display: flex; 
    }
    .search-bar input { 
      flex: 1; 
      padding: 10px; 
      border: none; 
      border-radius: 4px 0 0 4px; 
      outline: none; 
    }
    .search-bar button { 
      padding: 10px 20px; 
      border: none; 
      background: white; 
      border-radius: 0 4px 4px 0; 
      cursor: pointer; 
    }
    .nav-links { 
      display: flex; 
      align-items: center; 
      gap: 20px; 
    }
    .cart-link { 
      color: white; 
      text-decoration: none; 
    }
    .username { 
      background: rgba(255,255,255,0.2); 
      padding: 5px 12px; 
      border-radius: 20px; 
    }
    .logout-btn { 
      background: rgba(255,255,255,0.2); 
      border: none; 
      color: white; 
      padding: 5px 12px; 
      border-radius: 5px; 
      cursor: pointer; 
    }
    
    @media (max-width: 768px) { 
      .container { 
        flex-direction: column; 
      } 
      .search-bar { 
        max-width: 100%; 
        width: 100%; 
      }
      .nav-links { 
        width: 100%; 
        justify-content: center; 
      }
    }
  `]
})
export class HeaderComponent {
  private ecommerceService = inject(EcommerceService);
  
  cartCount = this.ecommerceService.cartCount;
  isLoggedIn = this.ecommerceService.isLoggedIn;
  username = () => this.ecommerceService.currentUser()?.username || '';
  
  // PASTE YOUR BASE64 STRING HERE
  // It should start with: data:image/jpeg;base64,  or data:image/png;base64,
  logoBase64 = 'data:image/jpeg;base64,';
  
  search(query: string) {
    if (query && query.trim()) {
      window.location.href = `/products?search=${encodeURIComponent(query)}`;
    }
  }
  
  logout() {
    this.ecommerceService.logout();
    window.location.href = '/products';
  }
}